
SET DEFINE OFF;

-- Dimension Tables
CREATE TABLE Dim_Date (
    date_key INT PRIMARY KEY,
    full_date DATE,
    day INT,
    day_name VARCHAR2(10),
    weekmonth INT,
    month_name VARCHAR2(20),
    quarter INT,
    year INT
);

CREATE TABLE Dim_Customer (
    customer_key INT PRIMARY KEY,
    customer_id VARCHAR2(20),
    customer_name VARCHAR2(100),
    gender VARCHAR2(10),
    age_group VARCHAR2(20),
    city VARCHAR2(100),
    region VARCHAR2(100),
    registration_date DATE,
    customer_segment VARCHAR2(50)
);

CREATE TABLE Dim_Product (
    product_key INT PRIMARY KEY,
    product_id VARCHAR2(20),
    product_name VARCHAR2(255),
    brand VARCHAR2(100),
    seasonal_flag CHAR(1),
    launch_date DATE
);

CREATE TABLE Dim_Category (
    category_key INT PRIMARY KEY,
    category_name VARCHAR2(100),
    sub_category VARCHAR2(100),
    parent_category VARCHAR2(100)
);

CREATE TABLE Dim_Payment (
    payment_key INT PRIMARY KEY,
    payment_method VARCHAR2(50)
);

CREATE TABLE Dim_Shipping (
    shipping_key INT PRIMARY KEY,
    shipping_type VARCHAR2(50),
    delivery_days INT
);

-- Fact Table
CREATE TABLE Fact_Order_Line (
    order_key INT PRIMARY KEY,
    order_id VARCHAR2(20),
    customer_key INT,
    product_key INT,
    date_key INT,
    category_key INT,
    payment_key INT,
    shipping_key INT,
    quantity INT,
    unit_price NUMBER(15, 2),
    unit_cost NUMBER(15, 2),
    discount_rate NUMBER(5, 2),
    customer_rating NUMBER(3, 1),
    gross_amount NUMBER(15, 2),
    discount_amount NUMBER(15, 2),
    net_amount NUMBER(15, 2),
    cost_amount NUMBER(15, 2),
    profit_amount NUMBER(15, 2),
    profit_margin NUMBER(15, 4),
    CONSTRAINT fk_date FOREIGN KEY (date_key) REFERENCES Dim_Date(date_key),
    CONSTRAINT fk_customer FOREIGN KEY (customer_key) REFERENCES Dim_Customer(customer_key),
    CONSTRAINT fk_product FOREIGN KEY (product_key) REFERENCES Dim_Product(product_key),
    CONSTRAINT fk_category FOREIGN KEY (category_key) REFERENCES Dim_Category(category_key),
    CONSTRAINT fk_payment FOREIGN KEY (payment_key) REFERENCES Dim_Payment(payment_key),
    CONSTRAINT fk_shipping FOREIGN KEY (shipping_key) REFERENCES Dim_Shipping(shipping_key)
);

